import Foundation

func solve(n: Int64, edges: [[Int64]]) -> Int64 {
    let adj = Array(repeating: [[Int64]](), count: Int(n))
    for edge in edges {
        let u = edge[0]
        let v = edge[1]
        let start = edge[2]
        let end = edge[3]
        adj[Int(u)].append([v, start, end])
    }

    let INF: Int64 = Int64(Int32.max)
    var dist = [Int64](repeating: INF, count: Int(n))
    dist[0] = 0

    var pq = [(Int64, Int64)]()
    pq.append((0, 0))

    // Custom priority queue using a min-heap
    while !pq.isEmpty {
        let (time, u) = pq.remove(at: 0)
        if u == Int(n) - 1 {
            return time
        }
        if time > dist[u] {
            continue
        }

        // Process edges
        for edge in adj[u] {
            let v = edge[0]
            let start = edge[1]
            let end = edge[2]
            if start <= time && time <= end {
                let newTime = time + 1
                if newTime < dist[v] {
                    dist[v] = newTime
                    pq.append((newTime, v))
                }
            }
        }

        // Stay at current node
        let newStayTime = time + 1
        if newStayTime < dist[u] {
            dist[u] = newStayTime
            pq.append((newStayTime, u))
        }
    }

    return -1
}
